var state = msg.payload && msg.payload.value && msg.payload.value.state;
if (state !== 'warning' && state !== 'alarm') { return null; }
msg.alert_path = msg.topic || msg.path || 'unknown';
msg.alert_state = state;
return msg;

var fs = global.get('fs') || require('fs');
var path = '/opt/d3kos/config/cloud-credentials.json';
try {
  if (!fs.existsSync(path)) { return null; }
  msg.credentials = JSON.parse(fs.readFileSync(path, 'utf8'));
} catch(e) {
  return null;
}
return msg;

var val = msg.payload && msg.payload.value || {};
var severity = msg.alert_state === 'alarm' ? 'CRITICAL' : 'WARNING';
msg.payload = {
  device_api_key: msg.credentials.device_api_key,
  boat_uuid: msg.credentials.boat_uuid,
  alert_type: msg.alert_path,
  severity: severity,
  message: val.message || '',
  method: val.method || '',
  timestamp: new Date().toISOString()
};
msg.headers = {
  'Content-Type': 'application/json',
  'Authorization': 'Bearer ' + msg.credentials.device_api_key
};
return msg;

var fs = global.get('fs') || require('fs');
try {
  var entry = JSON.stringify({ts: new Date().toISOString(), status: msg.statusCode, alert: msg.payload && msg.payload.alert_type}) + '\n';
  fs.appendFileSync('/opt/d3kos/data/alarm-webhook-log.jsonl', entry);
} catch(e){}
return null;

var fs = global.get('fs') || require('fs');
try {
  var entry = JSON.stringify({ts: new Date().toISOString(), error: msg.error || 'http-error', alert: msg.alert_path}) + '\n';
  fs.appendFileSync('/opt/d3kos/data/alarm-webhook-log.jsonl', entry);
} catch(e){}
return null;
